{"code": "import json
import re

# Load the BRCA alive patients data to get histotypes
file_path = locals()['var_functions.execute_python:60']
with open(file_path, 'r') as f:
    patient_data = json.load(f)

patient_histotype_map = patient_data['patient_histotype_map']

# BRCA alive patients with CDH1 mutations (from previous result)
cdh1_mutated_barcodes = ["TCGA-DK-A6AW", "TCGA-KQ-A41S", "TCGA-HQ-A2OF", "TCGA-H4-A2HQ", "TCGA-C4-A0F0", "TCGA-XF-A9T3", "TCGA-DK-A1AG"]

# Map histotypes for CDH1-mutated patients and count by histotype
cdh1_histotype_count = {}
for barcode in cdh1_mutated_barcodes:
    hist_type = patient_histotype_map.get(barcode)
    if hist_type:
        cdh1_histotype_count[hist_type] = cdh1_histotype_count.get(hist_type, 0) + 1

# Total BRCA alive patients by histotype (from previous data)
 histotype_patient_map = patient_data['histotype_patient_map']
histotype_totals = {k: len(v) for k, v in histotype_patient_map.items()}

# Calculate percentage for each histotype
percentage_by_histotype = {}
for hist_type, total_count in histotype_totals.items():
    cdh1_count = cdh1_histotype_count.get(hist_type, 0)
    percentage = (cdh1_count / total_count) * 100
    percentage_by_histotype[hist_type] = {
        'total_patients': total_count,
        'cdh1_mutated': cdh1_count,
        'percentage': percentage
    }

print("__RESULT__:")
print(json.dumps({
    'cdh1_mutated_barcodes': cdh1_mutated_barcodes,
    'cdh1_histotype_distribution': cdh1_histotype_count,
    'total_by_histotype': histotype_totals,
    'percentage_by_histotype': percentage_by_histotype
}))
